### 2. CONSTRAINT TYPES DEFINED IN SGLANG

The system supports the following constraint types:

| Constraint Type | Field Name | Location | Purpose |
|---|---|---|---|
| **JSON Schema** | `json_schema` | SamplingParams | Constrains output to valid JSON matching a schema |
| **Regex** | `regex` | SamplingParams | Constrains output to match a regex pattern |
| **EBNF** | `ebnf` | SamplingParams | Constrains output to match EBNF grammar |
| **Structural Tag** | `structural_tag` | SamplingParams | Constrains output with structural formatting (XGrammar feature) |
| **Stop Regex** | `stop_regex` | SamplingParams | Stops generation when pattern matches |

---

### 3. BASE CLASS HIERARCHY & INTERFACES

#### 3.1 SamplingParams (Top-level API) 
**File:** `/python/sglang/srt/sampling/sampling_params.py`

```python
class SamplingParams:
    def __init__(
        self,
        max_new_tokens: int = 128,
        ...
        json_schema: Optional[str] = None,      # JSON schema as string
        regex: Optional[str] = None,             # Regex pattern as string
        ebnf: Optional[str] = None,              # EBNF grammar as string
        structural_tag: Optional[str] = None,    # Structural tag definition
        stop_regex: Optional[Union[str, List[str]]] = None,
        ...
    ):
        self.json_schema = json_schema
        self.regex = regex
        self.ebnf = ebnf
        self.structural_tag = structural_tag
        self.stop_regex = stop_regex
        ...

    def verify(self, vocab_size):
        # Enforces mutual exclusivity
        grammars = [self.json_schema, self.regex, self.ebnf]
        if sum(x is not None for x in grammars) > 1:
            raise ValueError("Only one of regex, json_schema, or ebnf can be set.")
```

**Key Constraint:** Only ONE of `json_schema`, `regex`, or `ebnf` can be set at a time (mutually exclusive).

#### 3.2 BaseGrammarObject (Constraint Implementation Interface)
**File:** `/python/sglang/srt/constrained/base_grammar_backend.py`

```python
class BaseGrammarObject:
    """Base class for all constraint implementations"""

    def __init__(self):
        self._finished = False
        self.grammar_stats = None
        self.current_token = None

    def accept_token(self, token: int) -> None:
        """Accept a token in the constraint grammar"""
        raise NotImplementedError()

    def rollback(self, k: int):
        """Rollback the last k tokens"""
        raise NotImplementedError()

    def is_terminated(self):
        """Check if constraint is complete"""
        return False

    def allocate_vocab_mask(
        self, vocab_size: int, batch_size: int, device
    ) -> torch.Tensor:
        """Allocate mask for valid tokens"""
        raise NotImplementedError()

    def fill_vocab_mask(self, vocab_mask: torch.Tensor, idx: int) -> None:
        """Fill mask with allowed tokens for position idx"""
        raise NotImplementedError()

    @staticmethod
    def move_vocab_mask(vocab_mask: torch.Tensor, device) -> torch.Tensor:
        """Move vocab mask to device"""
        raise NotImplementedError()

    @staticmethod
    def apply_vocab_mask(logits: torch.Tensor, vocab_mask: torch.Tensor) -> None:
        """Apply mask to logits (set forbidden tokens to -inf)"""
        raise NotImplementedError()

    def copy(self) -> "BaseGrammarObject":
        """Create a copy for batch processing"""
        return self

    def try_jump_forward(self, tokenizer) -> Optional[Tuple[List[int], str]]:
        """Optimization: jump ahead in grammar when possible"""
        raise NotImplementedError()

    def jump_forward_str_state(self, helper: Tuple[List[int], str]) -> Tuple[str, int]:
        """Get string to jump to"""
        raise NotImplementedError()
```

#### 3.3 BaseGrammarBackend (Registration & Dispatch)
**File:** `/python/sglang/srt/constrained/base_grammar_backend.py`

```python
@dataclass
class GrammarStats:
    """Statistics for grammar compilation"""
    compilation_time: Optional[float] = None
    schema_count: Optional[int] = None
    ebnf_size: Optional[int] = None
    is_cache_hit: bool = False
    is_grammar_aborted: bool = False
    tree_traversal_time: List[float] = field(default_factory=list)
    dispatch_type: Optional[str] = None
    num_timeout: int = 0


class BaseGrammarBackend:
    """Base backend for constraint dispatch"""

    def __init__(self):
        self.executor = ThreadPoolExecutor()
        self.cache: Dict[Tuple[str, str], CacheEntry] = {}

    def dispatch_json(self, key_string: str) -> Optional[BaseGrammarObject]:
        """Dispatch JSON schema constraint"""
        return self._not_supported("json", key_string)

    def dispatch_regex(self, key_string: str) -> Optional[BaseGrammarObject]:
        """Dispatch regex constraint"""
        return self._not_supported("regex", key_string)

    def dispatch_ebnf(self, key_string: str) -> Optional[BaseGrammarObject]:
        """Dispatch EBNF constraint"""
        return self._not_supported("ebnf", key_string)

    def dispatch_structural_tag(self, key_string: str) -> Optional[BaseGrammarObject]:
        """Dispatch structural tag constraint"""
        return self._not_supported("structural_tag", key_string)

    def _init_value_dispatch(
        self, key: Tuple[str, str], require_reasoning: bool
    ) -> Optional[BaseGrammarObject]:
        """Internal dispatcher that routes to specific dispatch_X methods"""
        key_type, key_string = key
        if key_type == "json":
            grammar = self.dispatch_json(key_string)
        elif key_type == "regex":
            grammar = self.dispatch_regex(key_string)
        elif key_type == "ebnf":
            grammar = self.dispatch_ebnf(key_string)
        elif key_type == "structural_tag":
            grammar = self.dispatch_structural_tag(key_string)
        else:
            grammar = self.dispatch_fallback(key_type, key_string)
        return grammar

    def get_cached_or_future_value(
        self, key: Tuple[str, str], require_reasoning: bool
    ) -> Optional[BaseGrammarObject]:
        """Get cached constraint or submit for async compilation"""
        # Returns (value, cache_hit) where value is Future if not cached
```

**Backend Registry Pattern:**
```python
GRAMMAR_BACKEND_REGISTRY = {}

def register_grammar_backend(name, init_func):
    GRAMMAR_BACKEND_REGISTRY[name] = init_func

def create_grammar_backend(
    server_args: ServerArgs,
    tokenizer,
    vocab_size: int,
    eos_token_ids: Optional[set] = None,
) -> Optional[BaseGrammarBackend]:
    """Factory function that instantiates constraint backends"""
    # Checks custom registry first, then built-in backends
    if name in GRAMMAR_BACKEND_REGISTRY:
        return GRAMMAR_BACKEND_REGISTRY[name](...)

    if name == "outlines":
        from sglang.srt.constrained.outlines_backend import OutlinesGrammarBackend
        return OutlinesGrammarBackend(...)
    elif name == "xgrammar":
        from sglang.srt.constrained.xgrammar_backend import XGrammarGrammarBackend
        return XGrammarGrammarBackend(...)
    elif name == "llguidance":
        from sglang.srt.constrained.llguidance_backend import GuidanceBackend
        return GuidanceBackend(...)
    elif name == "none":
        return None
```

