class XGrammarGrammar(BaseGrammarObject):
    """Concrete implementation using XGrammar library"""

    def __init__(
        self,
        matcher: GrammarMatcher,  # XGrammar's matcher object
        vocab_size: int,
        ctx: CompiledGrammar,     # Compiled grammar from XGrammar
        override_stop_tokens: Optional[Union[List[int], int]],
        key_string: Optional[str] = None,
        grammar_stats: Optional[GrammarStats] = GrammarStats(),
    ):
        super().__init__()
        self.matcher = matcher
        self.vocab_size = vocab_size
        self.ctx = ctx
        self.accepted_tokens = []

    def accept_token(self, token: int):
        """Accept token if it satisfies the grammar"""
        if not self.is_terminated():
            accepted = self.matcher.accept_token(token)
            if not accepted:
                raise ValueError(f"Token {token} not accepted")
            self.accepted_tokens.append(token)

    def allocate_vocab_mask(
        self, vocab_size: int, batch_size: int, device
    ) -> torch.Tensor:
        """Allocate bitmask for valid tokens"""
        return allocate_token_bitmask(batch_size, vocab_size)

    def fill_vocab_mask(self, vocab_mask: torch.Tensor, idx: int) -> None:
        """Fill bitmask with valid tokens using matcher"""
        self.matcher.fill_next_token_bitmask(vocab_mask, idx)

    def is_terminated(self):
        """Check if grammar is complete"""
        return self.matcher.is_terminated()


class XGrammarGrammarBackend(BaseGrammarBackend):
    """XGrammar backend implementation"""

    def __init__(
        self,
        tokenizer,
        vocab_size: int,
        model_eos_token_ids: Optional[List[int]] = None,
        any_whitespace: bool = True,
    ):
        super().__init__()
        # Initialize XGrammar's compiler with tokenizer info
        tokenizer_info = TokenizerInfo.from_huggingface(
            tokenizer, vocab_size=vocab_size, stop_token_ids=model_eos_token_ids
        )
        self.grammar_compiler = GrammarCompiler(tokenizer_info=tokenizer_info)

    def dispatch_json(self, key_string: str) -> Optional[XGrammarGrammar]:
        """Compile JSON schema constraint"""
        try:
            if key_string == "$$ANY$$":
                ctx = self.grammar_compiler.compile_builtin_json_grammar()
            else:
                ctx = self.grammar_compiler.compile_json_schema(
                    schema=key_string, any_whitespace=self.any_whitespace
                )
        except (RuntimeError, json.decoder.JSONDecodeError) as e:
            logger.error(f"Invalid json_schema: {key_string=}, {e=}")
            return INVALID_GRAMMAR_OBJ
        return self._from_context(ctx, key_string, GrammarStats(dispatch_type="json"))

    def dispatch_regex(self, key_string: str) -> Optional[XGrammarGrammar]:
        """Compile regex constraint"""
        try:
            ctx = self.grammar_compiler.compile_regex(key_string)
        except RuntimeError as e:
            logger.error(f"Invalid regex: {key_string=}, {e=}")
            return INVALID_GRAMMAR_OBJ
        return self._from_context(ctx, key_string, GrammarStats(dispatch_type="regex"))

    def dispatch_ebnf(self, key_string: str) -> Optional[XGrammarGrammar]:
        """Compile EBNF constraint"""
        try:
            ctx = self.grammar_compiler.compile_grammar(key_string)
        except RuntimeError as e:
            logger.error(f"Invalid ebnf: {key_string=}, {e=}")
            return INVALID_GRAMMAR_OBJ
        return self._from_context(ctx, key_string, GrammarStats(dispatch_type="ebnf"))

    def dispatch_structural_tag(self, key_string: str) -> Optional[XGrammarGrammar]:
        """Compile structural tag constraint"""
        try:
            structural_tag = json.loads(key_string)
            # Handle both legacy and new structural tag formats
            tags = [
                StructuralTagItem(
                    begin=structure["begin"],
                    schema=json.dumps(structure["schema"]),
                    end=structure["end"],
                )
                for structure in structural_tag["structures"]
            ]
            ctx = self.grammar_compiler.compile_structural_tag(
                tags, structural_tag["triggers"]
            )
        except (RuntimeError, json.decoder.JSONDecodeError) as e:
            logger.error(f"Invalid structural_tag: {key_string=}, {e=}")
            return INVALID_GRAMMAR_OBJ
        return self._from_context(ctx, key_string, GrammarStats(dispatch_type="structural_tag"))
