### 6. JSON SCHEMA CONSTRAINT UTILITIES

**File:** `/python/sglang/srt/function_call/utils.py`

This file provides JSON schema generation specifically for function calling:

```python
def get_json_schema_constraint(
    tools: List[Tool], tool_choice: Union[ToolChoice, Literal["required"]]
) -> Optional[dict]:
    """
    Generate JSON schema constraint for tool/function calling.

    Returns:
        JSON schema as dict conforming to JSON Schema Draft 2020-12
    """
    if isinstance(tool_choice, ToolChoice):
        # Specific tool selected
        fn_name = tool_choice.function.name
        for tool in tools:
            if tool.function.name == fn_name:
                return {
                    "type": "array",
                    "minItems": 1,
                    "maxItems": 1,
                    "items": _get_tool_schema(tool),
                }
        return None
    elif tool_choice == "required":
        # Any tool is required
        json_schema = {
            "type": "array",
            "minItems": 1,
            "items": {
                "type": "object",
                "anyOf": [_get_tool_schema(tool) for tool in tools],
            },
        }
        json_schema_defs = _get_tool_schema_defs(tools)
        if json_schema_defs:
            json_schema["$defs"] = json_schema_defs
        return json_schema

    return None


def _get_tool_schema(tool: Tool) -> dict:
    """Get JSON schema for a single tool"""
    return {
        "properties": {
            "name": {"type": "string", "enum": [tool.function.name]},
            "parameters": (
                tool.function.parameters
                if tool.function.parameters
                else {"type": "object", "properties": {}}
            ),
        },
        "required": ["name", "parameters"],
    }


def _get_tool_schema_defs(tools: List[Tool]) -> dict:
    """
    Consolidate $defs from all tools with conflict detection

    Raises:
        ValueError: If conflicting $defs are found
    """
    all_defs = {}
    for tool in tools:
        if tool.function.parameters is None:
            continue
        defs = tool.function.parameters.get("$defs", {})
        for def_name, def_schema in defs.items():
            if def_name in all_defs and all_defs[def_name] != def_schema:
                raise ValueError(
                    f"Tool definition '{def_name}' has multiple schemas, "
                    "which is not supported."
                )
            else:
                all_defs[def_name] = def_schema
    return all_defs
```

