                    "temperature": 0 if n == 1 else 0.5,
                    "max_new_tokens": 128,
                    "n": n,
                    "regex": regex,  # Pass constraint here
                },
            },
        )

        # Verify output matches regex
        for item in response.json():
            text = item["text"].strip()
            if not re.match(regex, text):
                raise AssertionError(f"Text '{text}' doesn't match regex")

    def test_regex_generate_email(self):
        pattern = r"^user@example\.com$"
        self._run_decode_regex(regex=pattern, prompt="Generate an email:")

    def test_regex_generate_phone(self):
        pattern = r"^\(\d{3}\) \d{3}-\d{4}$"
        self._run_decode_regex(regex=pattern, prompt="Generate a phone number:")
```

---

### 12. MUTUALLY EXCLUSIVE CONSTRAINT VALIDATION

The system enforces strict mutual exclusivity at verification time:

```python
# From sampling_params.py
def verify(self, vocab_size):
    grammars = [
        self.json_schema,
        self.regex,
        self.ebnf,
    ]
    if sum(x is not None for x in grammars) > 1:
        raise ValueError(
            "Only one of regex, json_schema, or ebnf can be set."
        )
```

---

### 13. CONSTRAINT STATISTICS & MONITORING

All constraints track compilation and execution stats:

```python
@dataclass
class GrammarStats:
    compilation_time: Optional[float] = None      # How long to compile
    schema_count: Optional[int] = None            # JSON schema property count
    ebnf_size: Optional[int] = None               # EBNF grammar size
    is_cache_hit: bool = False                    # Was it cached?
    is_grammar_aborted: bool = False              # Did it fail?
    tree_traversal_time: List[float] = field(default_factory=list)
    dispatch_type: Optional[str] = None           # "json"/"regex"/"ebnf"/etc
    num_timeout: int = 0                          # Compilation timeouts
```

---

This comprehensive architecture allows SGLang to:
1. **Dynamically switch constraint backends** (XGrammar, Outlines, LLGuidance)
2. **Cache compiled constraints** for reuse across requests
3. **Compile constraints asynchronously** without blocking the main loop
4. **Apply efficient token-level masking** during generation
5. **Support new constraint types** through the backend registry

The key insight is the **separation of concerns**: constraint *definition* (what output to produce) is separate from constraint *implementation* (how to enforce it), allowing multiple backends to satisfy the same constraint interface.

